cardCss:
/*
 * STEAMPUNK
 * ─────────────────────────────────────────────────────────────────────────
 * Aesthetic : Victorian brass machinery + D&D 3E rulebook parchment —
 *             aged paper pages, iron chapter headers with gold rules,
 *             gear corner ornaments, IM Fell English body text
 * Fonts     : Cinzel Decorative (term header) · IM Fell English (body) ·
 *             Courier Prime (transliteration, tags)
 * Palette   : parchment #e8d5a8 · iron-black #1e1a16 · brass-gold #c8960a ·
 *             sepia-ink #3a1e08 · ash #7a6a54
 * Scoping   : all custom properties defined on .sp-card (not :root) to
 *             prevent leaking into the designer app chrome
 * Background: SVG feTurbulence paper-grain filter over parchment base,
 *             applied via absolutely-positioned overlay (.sp-paper-layer)
 */

@import url("https://fonts.googleapis.com/css2?family=Cinzel+Decorative:wght@400;700&family=Cinzel:wght@400;700&family=IM+Fell+English:ital@0;1&family=Courier+Prime:ital,wght@0,400;0,700;1,400&display=swap");
@import url("https://fonts.googleapis.com/css2?family=Shippori+Mincho+B1:wght@400;700;800&family=Zen+Old+Mincho:wght@400;700;900&family=Yuji+Syuku&family=Noto+Serif+JP:wght@400;700;900&display=swap");

.sp-card {
  /* ── scoped palette — no :root leak ── */
  --sp-parchment: #e8d5a8;
  --sp-iron:      #1e1a16;
  --sp-brass:     #c8960a;
  --sp-brass-dim: #8a6208;
  --sp-ink:       #3a1e08;
  --sp-ash:       #7a6a54;
  --sp-gold:      #f0b830;

  min-height: 100%;
  display: flex;
  flex-direction: column;
  background: var(--sp-parchment);
  position: relative;
  overflow: hidden;
  font-family: "IM Fell English", serif;
  color: var(--sp-ink);
  box-sizing: border-box;
  border: 2px solid var(--sp-brass-dim);
  box-shadow: inset 0 0 0 1px var(--sp-parchment), inset 0 0 0 3px var(--sp-brass-dim);
}

/* ── PAPER GRAIN OVERLAY ── */
.sp-paper-layer {
  position: absolute;
  inset: 0;
  pointer-events: none;
  z-index: 0;
  background: var(--sp-parchment);
  filter: url(#sp-paper);
  opacity: 0.7;
}

/* ── HEADER BAND ── */
.sp-header-band {
  position: relative;
  z-index: 1;
  background: var(--sp-iron);
  padding: 0.7rem 1.5rem 0.8rem;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.35rem;
}

.sp-header-rule {
  width: 100%;
  height: 1px;
  background: linear-gradient(to right, transparent, var(--sp-brass) 20%, var(--sp-gold) 50%, var(--sp-brass) 80%, transparent);
}

.sp-header-title {
  font-family: "Cinzel", serif;
  font-size: 1rem;
  font-weight: 700;
  letter-spacing: 0.35em;
  text-transform: uppercase;
  color: var(--sp-gold);
  text-shadow: 0 0 10px rgba(200,150,10,0.4);
  margin: 0;
}

/* ── MAIN CONTENT ── */
.sp-main-content {
  position: relative;
  z-index: 1;
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
  padding: 2rem 2rem 1.5rem;
}

.sp-prompt {
  font-family: "IM Fell English", serif;
  font-size: 1.6rem;
  font-style: italic;
  color: var(--sp-ink);
  margin: 0 0 1.2rem;
  line-height: 1.35;
  letter-spacing: 0.02em;
}

.sp-ornament {
  font-family: "Cinzel", serif;
  font-size: 0.75rem;
  color: var(--sp-brass);
  letter-spacing: 0.15em;
  margin: 0.4rem 0 1rem;
  opacity: 0.7;
  white-space: nowrap;
}

/* ── INPUT ── */
.sp-input-wrap { width: 100%; max-width: 26rem; }
.sp-input-wrap input {
  font-family: "IM Fell English", serif;
  font-size: 1.4rem;
  background: rgba(232,213,168,0.6);
  border: none;
  border-bottom: 2px solid var(--sp-brass-dim);
  color: var(--sp-ink);
  width: 100%;
  padding: 0.4rem 0;
  text-align: center;
  box-sizing: border-box;
  letter-spacing: 0.04em;
}
.sp-input-wrap input:focus {
  outline: none;
  border-bottom-color: var(--sp-brass);
  background: rgba(232,213,168,0.9);
}
.sp-input-wrap input::placeholder { color: var(--sp-ash); opacity: 0.7; }

.sp-hint-wrap { margin-top: 1rem; }
.sp-hint-link {
  font-family: "IM Fell English", serif;
  font-size: 1.9rem;
  font-style: italic;
  color: var(--sp-ash);
  text-decoration: underline;
  text-underline-offset: 2px;
}
.sp-hint-text {
  font-family: "IM Fell English", serif;
  font-size: 2rem;
  color: var(--sp-ink);
  opacity: 0.75;
  margin-top: 0.5rem;
}

/* ── BACK FIELDS ── */
.sp-term {
  font-family: "Cinzel Decorative", serif;
  font-size: 3.8rem;
  font-weight: 700;
  color: var(--sp-iron);
  margin: 0 0 0.5rem;
  line-height: 1.15;
  letter-spacing: 0.04em;
  text-shadow: 1px 1px 0 rgba(200,150,10,0.2);
}

.sp-reading {
  font-family: "IM Fell English", serif;
  font-size: 2rem;
  font-style: italic;
  color: var(--sp-brass-dim);
  margin: 0 0 0.2rem;
}

.sp-translation {
  font-family: "IM Fell English", serif;
  font-size: 3rem;
  color: var(--sp-ink);
  opacity: 0.85;
  margin: 0 0 0.2rem;
}

.sp-transliteration {
  font-family: "Courier Prime", monospace;
  font-size: 2.2rem;
  color: var(--sp-ash);
  font-style: italic;
  margin: 0;
}

.sp-tags {
  font-family: "Courier Prime", monospace;
  font-size: 1.6rem;
  color: var(--sp-ash);
  opacity: 0.6;
  margin: 0.6rem 0 0;
  letter-spacing: 0.1em;
  text-transform: uppercase;
}

.sp-picture img {
  max-width: 100%;
  max-height: 14rem;
  object-fit: contain;
  filter: sepia(0.6) contrast(1.05) brightness(0.9);
  margin-top: 1rem;
  border: 1px solid var(--sp-brass-dim);
  box-shadow: 2px 2px 6px rgba(58,30,8,0.25);
}

/* ── FOOTER BAND ── */
.sp-footer-band {
  position: relative;
  z-index: 1;
  background: var(--sp-iron);
  padding: 0.5rem 1.5rem;
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.sp-footer-rule {
  flex: 1;
  height: 1px;
  background: linear-gradient(to right, transparent, var(--sp-brass) 20%, var(--sp-gold) 50%, var(--sp-brass) 80%, transparent);
}

.sp-corner-gear {
  font-size: 1rem;
  color: var(--sp-brass);
  opacity: 0.65;
  line-height: 1;
}

.sp-audio { margin: 0 0 1rem; position: relative; z-index: 1; }

.append-play-btn-text a::after { content: "▶"; color: var(--sp-brass); font-size: 1.2rem; }
.append-play-btn-text svg { display: none; }
.append-play-btn-text button { font-size: 2.5rem; cursor: pointer; color: var(--sp-brass); }

/* ── FONT COMPARISON (temp — pick one for term+reading, then collapse) ── */
.sp-font-label {
  font-family: "Cinzel", serif;
  font-size: 0.75rem;
  letter-spacing: 0.3em;
  text-transform: uppercase;
  color: var(--sp-brass);
  opacity: 0.65;
  margin: 1rem 0 0;
}

.sp-term--shippori-b1,
.sp-reading--shippori-b1  { font-family: "Shippori Mincho B1", serif; }

.sp-term--zen-old,
.sp-reading--zen-old      { font-family: "Zen Old Mincho", serif; }

.sp-term--yuji,
.sp-reading--yuji         { font-family: "Yuji Syuku", serif; }

.sp-term--noto,
.sp-reading--noto         { font-family: "Noto Serif JP", serif; }
